INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('en-pl-v1', 'lesson-01', 'pronunciation', 10, 'Polish pronunciation', 'The sounds and letters that don''t exist in English — plus the digraphs that trip everyone up.', '{"id":"lesson-01","title":"Polish pronunciation","summary":"The sounds and letters that don''t exist in English — plus the digraphs that trip everyone up.","phonemes":[{"letter":"ą","name":"a-ogonek","ipa":"/ɔ̃/","englishApproximation":"Nasal ''o'' — like the French ''on'' in ''bon''.","description":"Nasal vowel. At word-end and before fricatives it stays a true nasal /ɔ̃/. Before stops it splits: /ɔm/ before p/b, /ɔn/ before t/d, /ɔŋ/ before k/g.","examples":[{"pl":"mąż","en":"husband"},{"pl":"wąż","en":"snake"},{"pl":"kąt","en":"corner"},{"pl":"miesiąc","en":"month"},{"pl":"pieniądze","en":"money"},{"pl":"ząb","en":"tooth"},{"pl":"dąb","en":"oak tree"},{"pl":"sąsiad","en":"neighbor"},{"pl":"gorąco","en":"hot"},{"pl":"pociąg","en":"train"}]},{"letter":"ę","name":"e-ogonek","ipa":"/ɛ̃/","englishApproximation":"Nasal ''e'' — like ''en'' in French ''vin'' but with an ''e'' base.","description":"Nasal vowel. At word-end it usually denasalizes to plain /ɛ/ in casual speech. Before stops it splits the same way as ą (em / en / eŋ).","examples":[{"pl":"ręka","en":"hand"},{"pl":"się","en":"oneself"},{"pl":"będę","en":"I will be"},{"pl":"pięć","en":"five"},{"pl":"język","en":"language / tongue"},{"pl":"gęś","en":"goose"},{"pl":"więc","en":"so / therefore"},{"pl":"dziękuję","en":"thank you"},{"pl":"częsty","en":"frequent"},{"pl":"tęsknić","en":"to miss (someone)"}]},{"letter":"ó","name":"o-kreska","ipa":"/u/","englishApproximation":"Identical to ''u'' — sounds like ''oo'' in ''boot''.","description":"Sounds exactly like the letter u. The two spellings are historical and you just have to memorize which word uses which. Often ó alternates with o in related forms (stół → stoły).","examples":[{"pl":"król","en":"king"},{"pl":"mówić","en":"to speak"},{"pl":"góra","en":"mountain"},{"pl":"córka","en":"daughter"},{"pl":"róża","en":"rose"},{"pl":"mózg","en":"brain"},{"pl":"pióro","en":"feather / pen"},{"pl":"róg","en":"horn / corner"},{"pl":"wróbel","en":"sparrow"},{"pl":"stół","en":"table"}]},{"letter":"y","name":"y","ipa":"/ɨ/","englishApproximation":"Like the ''i'' in ''bit'' but pulled further back in the mouth.","description":"A central vowel — not the English ''y''. Position your tongue between ''ee'' and ''uh''. It''s the default vowel after hard consonants (sz, cz, rz, ż, c, dz, r, ł).","examples":[{"pl":"ty","en":"you"},{"pl":"my","en":"we"},{"pl":"wy","en":"y''all"},{"pl":"syn","en":"son"},{"pl":"dobry","en":"good"},{"pl":"nowy","en":"new"},{"pl":"mysz","en":"mouse"},{"pl":"czy","en":"whether (question marker)"},{"pl":"ryba","en":"fish"},{"pl":"był","en":"was"}]},{"letter":"ł","name":"ł (l-with-stroke)","ipa":"/w/","englishApproximation":"Like English ''w'' in ''water''.","description":"Not an L sound at all — it''s an English ''w''. A frequent stumbling block: ''było'' is ''BIH-woh'', not ''BIH-loh''. Historically it was a velarized L, preserved only by some older speakers.","examples":[{"pl":"łatwy","en":"easy"},{"pl":"łyżka","en":"spoon"},{"pl":"mały","en":"small"},{"pl":"biały","en":"white"},{"pl":"głowa","en":"head"},{"pl":"słońce","en":"sun"},{"pl":"ciepło","en":"warm / warmth"},{"pl":"miły","en":"nice / kind"},{"pl":"stół","en":"table"},{"pl":"był","en":"was"}]},{"letter":"w","name":"w","ipa":"/v/","englishApproximation":"Like English ''v'' in ''van''.","description":"Always a V sound — never the English ''w''. Devoices to /f/ at word-end or next to voiceless consonants (e.g. ''w'' alone, used as a preposition before voiceless consonants).","examples":[{"pl":"woda","en":"water"},{"pl":"wino","en":"wine"},{"pl":"wiatr","en":"wind"},{"pl":"wieczór","en":"evening"},{"pl":"wszystko","en":"everything"},{"pl":"wesoły","en":"cheerful"},{"pl":"wielki","en":"big"},{"pl":"widzieć","en":"to see"},{"pl":"wracać","en":"to return"},{"pl":"wnuk","en":"grandson"}]},{"letter":"c","name":"c","ipa":"/ts/","englishApproximation":"Like ''ts'' in ''cats''.","description":"Always /ts/ — never the English ''k'' or ''s''. Before i it palatalizes (see ć).","examples":[{"pl":"co","en":"what"},{"pl":"cukier","en":"sugar"},{"pl":"cena","en":"price"},{"pl":"noc","en":"night"},{"pl":"serce","en":"heart"},{"pl":"praca","en":"work"},{"pl":"owoce","en":"fruits"},{"pl":"ojciec","en":"father"},{"pl":"miesiąc","en":"month"},{"pl":"cebula","en":"onion"}]},{"letter":"ch","name":"ch (= h)","ipa":"/x/","englishApproximation":"Like the German ''ch'' in ''Bach'' — a raspy back-of-throat H.","description":"Identical in sound to the letter ''h''. A bit raspier than English H. The two spellings (ch vs h) are historical and must be memorized per word.","examples":[{"pl":"chleb","en":"bread"},{"pl":"chłopak","en":"boy"},{"pl":"chata","en":"cottage"},{"pl":"chodzić","en":"to walk"},{"pl":"schody","en":"stairs"},{"pl":"chory","en":"sick"},{"pl":"mucha","en":"fly (insect)"},{"pl":"ucho","en":"ear"},{"pl":"dach","en":"roof"},{"pl":"choroba","en":"illness"}]},{"letter":"r","name":"r","ipa":"/r/","englishApproximation":"A tapped/trilled R like Spanish or Italian — never the English R.","description":"A short alveolar trill: the tip of the tongue taps just behind the upper teeth. Most often a single tap; in careful or emphatic speech a full trill.","examples":[{"pl":"rok","en":"year"},{"pl":"ranek","en":"morning"},{"pl":"ryba","en":"fish"},{"pl":"rower","en":"bicycle"},{"pl":"brat","en":"brother"},{"pl":"prawda","en":"truth"},{"pl":"kura","en":"hen"},{"pl":"dobry","en":"good"},{"pl":"środa","en":"Wednesday"},{"pl":"brzeg","en":"shore / edge"}]},{"letter":"ć","name":"ć / ci","ipa":"/t͡ɕ/","englishApproximation":"A very soft, hissy ''ch'' — like ''ch'' in ''cheese'' but with the tongue further forward and softer.","description":"The ''soft'' version of cz. Written ć at end of words or before consonants; written ''ci'' before a vowel (cia, cie, cio, ciu) and ''ci'' alone when followed by another consonant.","examples":[{"pl":"być","en":"to be"},{"pl":"iść","en":"to go"},{"pl":"pięć","en":"five"},{"pl":"dziesięć","en":"ten"},{"pl":"kość","en":"bone"},{"pl":"miłość","en":"love"},{"pl":"gość","en":"guest"},{"pl":"ciało","en":"body"},{"pl":"ciemny","en":"dark"},{"pl":"ciocia","en":"aunt"}]},{"letter":"ś","name":"ś / si","ipa":"/ɕ/","englishApproximation":"A very soft, hissy ''sh'' — like the ''sh'' in ''sheep'' but more whispery, tongue forward.","description":"The ''soft'' version of sz. Written ś before consonants and at word-end; written ''si'' before a vowel (sia, sie, sio, siu).","examples":[{"pl":"śnieg","en":"snow"},{"pl":"ślub","en":"wedding"},{"pl":"świat","en":"world"},{"pl":"środa","en":"Wednesday"},{"pl":"ślimak","en":"snail"},{"pl":"śmiech","en":"laughter"},{"pl":"święto","en":"holiday"},{"pl":"ścieżka","en":"path"},{"pl":"ślad","en":"trace / footprint"},{"pl":"prosić","en":"to ask / request"}]},{"letter":"ń","name":"ń / ni","ipa":"/ɲ/","englishApproximation":"Soft palatal ''n'' — like Spanish ''ñ'' in ''mañana''.","description":"The ''soft'' version of n. Written ń before consonants and at word-end; written ''ni'' before a vowel.","examples":[{"pl":"koń","en":"horse"},{"pl":"dzień","en":"day"},{"pl":"słońce","en":"sun"},{"pl":"dłoń","en":"palm of hand"},{"pl":"tańczyć","en":"to dance"},{"pl":"kończyć","en":"to finish"},{"pl":"pieśń","en":"song"},{"pl":"niania","en":"nanny"},{"pl":"jesień","en":"autumn"},{"pl":"ogień","en":"fire"}]},{"letter":"ż","name":"ż (z-dot)","ipa":"/ʐ/","englishApproximation":"Like the ''s'' in ''measure'' or French ''j'' in ''jour'' — but harder, with the tongue curled back.","description":"A retroflex ''zh''. Identical in sound to the digraph ''rz'' (which you''ll meet separately). The two spellings are historical.","examples":[{"pl":"żaba","en":"frog"},{"pl":"żona","en":"wife"},{"pl":"żółty","en":"yellow"},{"pl":"żyć","en":"to live"},{"pl":"żelazo","en":"iron"},{"pl":"żart","en":"joke"},{"pl":"już","en":"already"},{"pl":"mąż","en":"husband"},{"pl":"nóż","en":"knife"},{"pl":"róża","en":"rose"}]},{"letter":"rz","name":"rz (= ż)","ipa":"/ʐ/","englishApproximation":"Same sound as ż — like ''zh'' in ''measure'', harder.","description":"Pronounced identically to ż. Devoices to /ʂ/ (like sz) when adjacent to voiceless consonants — e.g. ''przepraszam'' starts with a /pʂ/. The spelling is preserved because it often alternates with r in related words (morze ↔ morski).","examples":[{"pl":"rzeka","en":"river"},{"pl":"morze","en":"sea"},{"pl":"drzewo","en":"tree"},{"pl":"trzy","en":"three"},{"pl":"przyjaciel","en":"friend"},{"pl":"przed","en":"before / in front of"},{"pl":"korzeń","en":"root"},{"pl":"grzyb","en":"mushroom"},{"pl":"brzeg","en":"shore"},{"pl":"wierzba","en":"willow"}]},{"letter":"ź","name":"ź / zi","ipa":"/ʑ/","englishApproximation":"A very soft ''zh'' — like the ''s'' in ''vision'' but more whispery, tongue forward.","description":"The ''soft'' counterpart of ż. Written ź before consonants and at word-end; written ''zi'' before a vowel (zia, zie, zio, ziu).","examples":[{"pl":"źle","en":"badly"},{"pl":"źrebak","en":"foal"},{"pl":"źródło","en":"source / spring"},{"pl":"gałąź","en":"branch"},{"pl":"weź","en":"take! (imperative)"},{"pl":"nieźle","en":"not bad"},{"pl":"gryźć","en":"to bite"},{"pl":"jeździć","en":"to ride / travel"},{"pl":"zima","en":"winter"},{"pl":"ziemia","en":"earth / ground"}]},{"letter":"sz","name":"sz","ipa":"/ʂ/","englishApproximation":"Like English ''sh'' in ''ship'' but harder, with the tongue curled back.","description":"The ''hard'' sh. Tongue is pulled back and slightly curled. Followed by y (not i): szyba, szykować.","examples":[{"pl":"szkoła","en":"school"},{"pl":"szybko","en":"quickly"},{"pl":"szczęście","en":"luck / happiness"},{"pl":"szafa","en":"wardrobe"},{"pl":"proszę","en":"please / here you go"},{"pl":"pieszo","en":"on foot"},{"pl":"kasza","en":"groats / porridge"},{"pl":"szalik","en":"scarf"},{"pl":"wszystko","en":"everything"},{"pl":"mysz","en":"mouse"}]},{"letter":"cz","name":"cz","ipa":"/t͡ʂ/","englishApproximation":"Like English ''ch'' in ''church'' but harder, with the tongue curled back.","description":"The ''hard'' ch. Followed by y (not i): czysty, czyj. Compare with the much softer ć.","examples":[{"pl":"czas","en":"time"},{"pl":"czy","en":"whether"},{"pl":"czekać","en":"to wait"},{"pl":"oczy","en":"eyes"},{"pl":"czysty","en":"clean"},{"pl":"czerwony","en":"red"},{"pl":"czarny","en":"black"},{"pl":"klucz","en":"key"},{"pl":"część","en":"part"},{"pl":"wczoraj","en":"yesterday"}]},{"letter":"dz","name":"dz","ipa":"/d͡z/","englishApproximation":"Like the ''ds'' in ''beds'' or ''kids''.","description":"A single voiced affricate — say it in one push, not ''d'' + ''z''. The voiced counterpart of c.","examples":[{"pl":"bardzo","en":"very"},{"pl":"widzieć","en":"to see"},{"pl":"dzwon","en":"bell"},{"pl":"dzban","en":"jug"},{"pl":"godzina","en":"hour"},{"pl":"nadzieja","en":"hope"},{"pl":"sadza","en":"soot"},{"pl":"idzie","en":"(he/she) goes"},{"pl":"dzielić","en":"to divide / share"},{"pl":"pieniądze","en":"money"}]},{"letter":"dź","name":"dź / dzi","ipa":"/d͡ʑ/","englishApproximation":"A soft ''j'' sound — like ''j'' in ''jeans'' but lighter, tongue further forward.","description":"The voiced counterpart of ć. Written dź before consonants and at word-end; written ''dzi'' before a vowel.","examples":[{"pl":"dźwięk","en":"sound"},{"pl":"niedźwiedź","en":"bear"},{"pl":"idź","en":"go! (imperative)"},{"pl":"łódź","en":"boat / Łódź (city)"},{"pl":"gwóźdź","en":"nail"},{"pl":"dziadek","en":"grandfather"},{"pl":"dziecko","en":"child"},{"pl":"dzień","en":"day"},{"pl":"dziś","en":"today"},{"pl":"poniedziałek","en":"Monday"}]},{"letter":"dż","name":"dż","ipa":"/d͡ʐ/","englishApproximation":"Like English ''j'' in ''jungle'' — the hard, retroflex version.","description":"The voiced counterpart of cz. Mostly appears in loanwords (dżem, dżinsy) and a handful of native words (drożdże).","examples":[{"pl":"dżem","en":"jam (preserve)"},{"pl":"dżinsy","en":"jeans"},{"pl":"dżungla","en":"jungle"},{"pl":"brydż","en":"bridge (card game)"},{"pl":"dżentelmen","en":"gentleman"},{"pl":"dżin","en":"gin"},{"pl":"drożdże","en":"yeast"},{"pl":"gadżet","en":"gadget"},{"pl":"dżuma","en":"plague"},{"pl":"dżip","en":"jeep"}]}]}');
INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('en-pl-v1', 'lesson-02', 'verbs', 20, 'Lesson 2 — Core verbs', '11 high-frequency Polish verbs in the present tense, grouped by conjugation pattern. Tap a verb to see its full paradigm, or pick a pronoun to drill one form across every verb.', '{"id":"lesson-02","title":"Lesson 2 — Core verbs","summary":"11 high-frequency Polish verbs in the present tense, grouped by conjugation pattern. Tap a verb to see its full paradigm, or pick a pronoun to drill one form across every verb.","verbs":[{"lemma":"być","en":"to be","forms":{"1sg":"jestem","2sg":"jesteś","3sg":"jest","1pl":"jesteśmy","2pl":"jesteście","3pl":"są"},"past_forms":{"1sg":"byłem","2sg":"byłeś","3sg":"był","1pl":"byliśmy","2pl":"byliście","3pl":"byli"}},{"lemma":"mieć","en":"to have","forms":{"1sg":"mam","2sg":"masz","3sg":"ma","1pl":"mamy","2pl":"macie","3pl":"mają"},"past_forms":{"1sg":"miałem","2sg":"miałeś","3sg":"miał","1pl":"mieliśmy","2pl":"mieliście","3pl":"mieli"}},{"lemma":"iść","en":"to go","forms":{"1sg":"idę","2sg":"idziesz","3sg":"idzie","1pl":"idziemy","2pl":"idziecie","3pl":"idą"},"past_forms":{"1sg":"szedłem","2sg":"szedłeś","3sg":"szedł","1pl":"szliśmy","2pl":"szliście","3pl":"szli"}},{"lemma":"jeść","en":"to eat","forms":{"1sg":"jem","2sg":"jesz","3sg":"je","1pl":"jemy","2pl":"jecie","3pl":"jedzą"},"past_forms":{"1sg":"jadłem","2sg":"jadłeś","3sg":"jadł","1pl":"jedliśmy","2pl":"jedliście","3pl":"jedli"}},{"lemma":"pić","en":"to drink","forms":{"1sg":"piję","2sg":"pijesz","3sg":"pije","1pl":"pijemy","2pl":"pijecie","3pl":"piją"},"past_forms":{"1sg":"piłem","2sg":"piłeś","3sg":"pił","1pl":"piliśmy","2pl":"piliście","3pl":"pili"}},{"lemma":"robić","en":"to do","forms":{"1sg":"robię","2sg":"robisz","3sg":"robi","1pl":"robimy","2pl":"robicie","3pl":"robią"},"past_forms":{"1sg":"robiłem","2sg":"robiłeś","3sg":"robił","1pl":"robiliśmy","2pl":"robiliście","3pl":"robili"}},{"lemma":"mówić","en":"to speak","forms":{"1sg":"mówię","2sg":"mówisz","3sg":"mówi","1pl":"mówimy","2pl":"mówicie","3pl":"mówią"},"past_forms":{"1sg":"mówiłem","2sg":"mówiłeś","3sg":"mówił","1pl":"mówiliśmy","2pl":"mówiliście","3pl":"mówili"}},{"lemma":"widzieć","en":"to see","forms":{"1sg":"widzę","2sg":"widzisz","3sg":"widzi","1pl":"widzimy","2pl":"widzicie","3pl":"widzą"},"past_forms":{"1sg":"widziałem","2sg":"widziałeś","3sg":"widział","1pl":"widzieliśmy","2pl":"widzieliście","3pl":"widzieli"}},{"lemma":"lubić","en":"to like","forms":{"1sg":"lubię","2sg":"lubisz","3sg":"lubi","1pl":"lubimy","2pl":"lubicie","3pl":"lubią"},"past_forms":{"1sg":"lubiłem","2sg":"lubiłeś","3sg":"lubił","1pl":"lubiliśmy","2pl":"lubiliście","3pl":"lubili"}},{"lemma":"czytać","en":"to read","forms":{"1sg":"czytam","2sg":"czytasz","3sg":"czyta","1pl":"czytamy","2pl":"czytacie","3pl":"czytają"},"past_forms":{"1sg":"czytałem","2sg":"czytałeś","3sg":"czytał","1pl":"czytaliśmy","2pl":"czytaliście","3pl":"czytali"}},{"lemma":"płacić","en":"to pay","forms":{"1sg":"płacę","2sg":"płacisz","3sg":"płaci","1pl":"płacimy","2pl":"płacicie","3pl":"płacą"},"past_forms":{"1sg":"płaciłem","2sg":"płaciłeś","3sg":"płacił","1pl":"płaciliśmy","2pl":"płaciliście","3pl":"płacili"}},{"lemma":"wiedzieć","en":"to know (a fact)","forms":{"1sg":"wiem","2sg":"wiesz","3sg":"wie","1pl":"wiemy","2pl":"wiecie","3pl":"wiedzą"},"past_forms":{"1sg":"wiedziałem","2sg":"wiedziałeś","3sg":"wiedział","1pl":"wiedzieliśmy","2pl":"wiedzieliście","3pl":"wiedzieli"}},{"lemma":"znać","en":"to know (a person/thing)","forms":{"1sg":"znam","2sg":"znasz","3sg":"zna","1pl":"znamy","2pl":"znacie","3pl":"znają"},"past_forms":{"1sg":"znałem","2sg":"znałeś","3sg":"znał","1pl":"znaliśmy","2pl":"znaliście","3pl":"znali"}},{"lemma":"chcieć","en":"to want","forms":{"1sg":"chcę","2sg":"chcesz","3sg":"chce","1pl":"chcemy","2pl":"chcecie","3pl":"chcą"},"past_forms":{"1sg":"chciałem","2sg":"chciałeś","3sg":"chciał","1pl":"chcieliśmy","2pl":"chcieliście","3pl":"chcieli"}},{"lemma":"móc","en":"can / to be able","forms":{"1sg":"mogę","2sg":"możesz","3sg":"może","1pl":"możemy","2pl":"możecie","3pl":"mogą"},"past_forms":{"1sg":"mogłem","2sg":"mogłeś","3sg":"mógł","1pl":"mogliśmy","2pl":"mogliście","3pl":"mogli"}},{"lemma":"musieć","en":"must / have to","forms":{"1sg":"muszę","2sg":"musisz","3sg":"musi","1pl":"musimy","2pl":"musicie","3pl":"muszą"},"past_forms":{"1sg":"musiałem","2sg":"musiałeś","3sg":"musiał","1pl":"musieliśmy","2pl":"musieliście","3pl":"musieli"}},{"lemma":"pisać","en":"to write","forms":{"1sg":"piszę","2sg":"piszesz","3sg":"pisze","1pl":"piszemy","2pl":"piszecie","3pl":"piszą"},"past_forms":{"1sg":"pisałem","2sg":"pisałeś","3sg":"pisał","1pl":"pisaliśmy","2pl":"pisaliście","3pl":"pisali"}},{"lemma":"kupować","en":"to buy","forms":{"1sg":"kupuję","2sg":"kupujesz","3sg":"kupuje","1pl":"kupujemy","2pl":"kupujecie","3pl":"kupują"},"past_forms":{"1sg":"kupowałem","2sg":"kupowałeś","3sg":"kupował","1pl":"kupowaliśmy","2pl":"kupowaliście","3pl":"kupowali"}},{"lemma":"mieszkać","en":"to live (reside)","forms":{"1sg":"mieszkam","2sg":"mieszkasz","3sg":"mieszka","1pl":"mieszkamy","2pl":"mieszkacie","3pl":"mieszkają"},"past_forms":{"1sg":"mieszkałem","2sg":"mieszkałeś","3sg":"mieszkał","1pl":"mieszkaliśmy","2pl":"mieszkaliście","3pl":"mieszkali"}},{"lemma":"pracować","en":"to work","forms":{"1sg":"pracuję","2sg":"pracujesz","3sg":"pracuje","1pl":"pracujemy","2pl":"pracujecie","3pl":"pracują"},"past_forms":{"1sg":"pracowałem","2sg":"pracowałeś","3sg":"pracował","1pl":"pracowaliśmy","2pl":"pracowaliście","3pl":"pracowali"}},{"lemma":"rozumieć","en":"to understand","forms":{"1sg":"rozumiem","2sg":"rozumiesz","3sg":"rozumie","1pl":"rozumiemy","2pl":"rozumiecie","3pl":"rozumieją"},"past_forms":{"1sg":"rozumiałem","2sg":"rozumiałeś","3sg":"rozumiał","1pl":"rozumieliśmy","2pl":"rozumieliście","3pl":"rozumieli"}},{"lemma":"spać","en":"to sleep","forms":{"1sg":"śpię","2sg":"śpisz","3sg":"śpi","1pl":"śpimy","2pl":"śpicie","3pl":"śpią"},"past_forms":{"1sg":"spałem","2sg":"spałeś","3sg":"spał","1pl":"spaliśmy","2pl":"spaliście","3pl":"spali"}},{"lemma":"spotykać","en":"to meet","forms":{"1sg":"spotykam","2sg":"spotykasz","3sg":"spotyka","1pl":"spotykamy","2pl":"spotykacie","3pl":"spotykają"},"past_forms":{"1sg":"spotykałem","2sg":"spotykałeś","3sg":"spotykał","1pl":"spotykaliśmy","2pl":"spotykaliście","3pl":"spotykali"}},{"lemma":"pamiętać","en":"to remember","forms":{"1sg":"pamiętam","2sg":"pamiętasz","3sg":"pamięta","1pl":"pamiętamy","2pl":"pamiętacie","3pl":"pamiętają"},"past_forms":{"1sg":"pamiętałem","2sg":"pamiętałeś","3sg":"pamiętał","1pl":"pamiętaliśmy","2pl":"pamiętaliście","3pl":"pamiętali"}},{"lemma":"tańczyć","en":"to dance","forms":{"1sg":"tańczę","2sg":"tańczysz","3sg":"tańczy","1pl":"tańczymy","2pl":"tańczycie","3pl":"tańczą"},"past_forms":{"1sg":"tańczyłem","2sg":"tańczyłeś","3sg":"tańczył","1pl":"tańczyliśmy","2pl":"tańczyliście","3pl":"tańczyli"}},{"lemma":"całować","en":"to kiss","forms":{"1sg":"całuję","2sg":"całujesz","3sg":"całuje","1pl":"całujemy","2pl":"całujecie","3pl":"całują"},"past_forms":{"1sg":"całowałem","2sg":"całowałeś","3sg":"całował","1pl":"całowaliśmy","2pl":"całowaliście","3pl":"całowali"}},{"lemma":"czekać","en":"to wait","forms":{"1sg":"czekam","2sg":"czekasz","3sg":"czeka","1pl":"czekamy","2pl":"czekacie","3pl":"czekają"},"past_forms":{"1sg":"czekałem","2sg":"czekałeś","3sg":"czekał","1pl":"czekaliśmy","2pl":"czekaliście","3pl":"czekali"}},{"lemma":"dzwonić","en":"to call (phone)","forms":{"1sg":"dzwonię","2sg":"dzwonisz","3sg":"dzwoni","1pl":"dzwonimy","2pl":"dzwonicie","3pl":"dzwonią"},"past_forms":{"1sg":"dzwoniłem","2sg":"dzwoniłeś","3sg":"dzwonił","1pl":"dzwoniliśmy","2pl":"dzwoniliście","3pl":"dzwonili"}},{"lemma":"czuć","en":"to feel","forms":{"1sg":"czuję","2sg":"czujesz","3sg":"czuje","1pl":"czujemy","2pl":"czujecie","3pl":"czują"},"past_forms":{"1sg":"czułem","2sg":"czułeś","3sg":"czuł","1pl":"czuliśmy","2pl":"czuliście","3pl":"czuli"}},{"lemma":"kochać","en":"to love","forms":{"1sg":"kocham","2sg":"kochasz","3sg":"kocha","1pl":"kochamy","2pl":"koc