,"forms":{"1sg":"pytam","2sg":"pytasz","3sg":"pyta","1pl":"pytamy","2pl":"pytacie","3pl":"pytają"},"past_forms":{"1sg":"pytałem","2sg":"pytałeś","3sg":"pytał","1pl":"pytaliśmy","2pl":"pytaliście","3pl":"pytali"}}],"pronouns":[{"lemma":"ja","en":"I","case_forms":{"nom":"ja","acc":"mnie","dat":"mi"}},{"lemma":"ty","en":"you","case_forms":{"nom":"ty","acc":"cię","dat":"ci"}},{"lemma":"on","en":"he","case_forms":{"nom":"on","acc":"go","dat":"mu"}},{"lemma":"ona","en":"she","case_forms":{"nom":"ona","acc":"ją","dat":"jej"}},{"lemma":"ono","en":"it","case_forms":{"nom":"ono","acc":"je","dat":"mu"}},{"lemma":"my","en":"we","case_forms":{"nom":"my","acc":"nas","dat":"nam"}},{"lemma":"wy","en":"y''all","case_forms":{"nom":"wy","acc":"was","dat":"wam"}},{"lemma":"oni","en":"they (men/mixed)","case_forms":{"nom":"oni","acc":"ich","dat":"im"}},{"lemma":"one","en":"they (others)","case_forms":{"nom":"one","acc":"je","dat":"im"}}],"phrases":[{"en":"I see her","pl":"Widzę ją","focus":["verb.present.1sg","pronoun.acc.3sg.f"]},{"en":"She sees me","pl":"Ona mnie widzi","focus":["verb.present.3sg","pronoun.acc.1sg"]},{"en":"You like him","pl":"Lubisz go","focus":["verb.present.2sg","pronoun.acc.3sg.m"]},{"en":"He likes you","pl":"On cię lubi","focus":["verb.present.3sg","pronoun.acc.2sg"]},{"en":"We know them","pl":"My ich znamy","focus":["verb.present.1pl","pronoun.acc.3pl.m"]},{"en":"They see us","pl":"Oni nas widzą","focus":["verb.present.3pl","pronoun.acc.1pl"]},{"en":"I pay you","pl":"Płacę ci","focus":["verb.present.1sg","pronoun.dat.2sg"]},{"en":"She pays him","pl":"Ona mu płaci","focus":["verb.present.3sg","pronoun.dat.3sg.m"]},{"en":"I have a dog","pl":"Mam psa","focus":["verb.present.1sg"]},{"en":"We eat bread","pl":"Jemy chleb","focus":["verb.present.1pl"]},{"en":"He drinks water","pl":"On pije wodę","focus":["verb.present.3sg"]},{"en":"I am happy","pl":"Jestem szczęśliwy","focus":["verb.present.1sg.być"]},{"en":"You are tired","pl":"Jesteś zmęczony","focus":["verb.present.2sg.być"]},{"en":"They read books","pl":"Oni czytają książki","focus":["verb.present.3pl"]},{"en":"I do it","pl":"Robię to","focus":["verb.present.1sg"]},{"en":"She speaks Polish","pl":"Ona mówi po polsku","focus":["verb.present.3sg"]},{"en":"I go to the store","pl":"Idę do sklepu","focus":["verb.present.1sg.iść"]},{"en":"I know him","pl":"Znam go","focus":["verb.present.1sg","pronoun.acc.3sg.m"]},{"en":"She knows the answer","pl":"Ona zna odpowiedź","focus":["verb.present.3sg.znać"]},{"en":"I don''t know","pl":"Nie wiem","focus":["verb.present.1sg.wiedzieć"]},{"en":"I want coffee","pl":"Chcę kawę","focus":["verb.present.1sg.chcieć"]},{"en":"We can help","pl":"Możemy pomóc","focus":["verb.present.1pl.móc"]},{"en":"You must go","pl":"Musisz iść","focus":["verb.present.2sg.musieć"]},{"en":"I write a letter","pl":"Piszę list","focus":["verb.present.1sg.pisać"]},{"en":"We buy bread","pl":"Kupujemy chleb","focus":["verb.present.1pl.kupować"]},{"en":"I live in Warsaw","pl":"Mieszkam w Warszawie","focus":["verb.present.1sg.mieszkać"]},{"en":"He works at home","pl":"On pracuje w domu","focus":["verb.present.3sg.pracować"]},{"en":"I understand you","pl":"Rozumiem cię","focus":["verb.present.1sg.rozumieć","pronoun.acc.2sg"]},{"en":"They want water","pl":"Oni chcą wodę","focus":["verb.present.3pl.chcieć"]},{"en":"She has a cat","pl":"Ona ma kota","focus":["verb.present.3sg.mieć"]},{"en":"We are at home","pl":"Jesteśmy w domu","focus":["verb.present.1pl.być"]},{"en":"You drink tea","pl":"Pijesz herbatę","focus":["verb.present.2sg.pić"]},{"en":"I read a book","pl":"Czytam książkę","focus":["verb.present.1sg.czytać"]},{"en":"She sleeps well","pl":"Ona śpi dobrze","focus":["verb.present.3sg.spać"]}]}');
INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('en-pl-v1', 'lesson-03', 'adjectives', 30, 'Lesson 3 — Core adjectives', 'High-frequency Polish adjectives. Each one is shown in all five nominative forms (m / f / n / virile-pl / other-pl) and all five accusative forms — accusative is the case you need to say things like ''I see a big table''. Masculine accusative defaults to the animate ending (-ego); for inanimate nouns the masculine accusative is identical to the nominative (duży stół, not dużego stół).', '{"id":"lesson-03","title":"Lesson 3 — Core adjectives","summary":"High-frequency Polish adjectives. Each one is shown in all five nominative forms (m / f / n / virile-pl / other-pl) and all five accusative forms — accusative is the case you need to say things like ''I see a big table''. Masculine accusative defaults to the animate ending (-ego); for inanimate nouns the masculine accusative is identical to the nominative (duży stół, not dużego stół).","adjectives":[{"lemma":"dobry","en":"good","nom":{"m":"dobry","f":"dobra","n":"dobre","mp":"dobrzy","other":"dobre"},"acc":{"m":"dobrego","f":"dobrą","n":"dobre","mp":"dobrych","other":"dobre"}},{"lemma":"zły","en":"bad","nom":{"m":"zły","f":"zła","n":"złe","mp":"źli","other":"złe"},"acc":{"m":"złego","f":"złą","n":"złe","mp":"złych","other":"złe"}},{"lemma":"nowy","en":"new","nom":{"m":"nowy","f":"nowa","n":"nowe","mp":"nowi","other":"nowe"},"acc":{"m":"nowego","f":"nową","n":"nowe","mp":"nowych","other":"nowe"}},{"lemma":"stary","en":"old","nom":{"m":"stary","f":"stara","n":"stare","mp":"starzy","other":"stare"},"acc":{"m":"starego","f":"starą","n":"stare","mp":"starych","other":"stare"}},{"lemma":"duży","en":"big","nom":{"m":"duży","f":"duża","n":"duże","mp":"duzi","other":"duże"},"acc":{"m":"dużego","f":"dużą","n":"duże","mp":"dużych","other":"duże"}},{"lemma":"mały","en":"small","nom":{"m":"mały","f":"mała","n":"małe","mp":"mali","other":"małe"},"acc":{"m":"małego","f":"małą","n":"małe","mp":"małych","other":"małe"}},{"lemma":"wielki","en":"great","nom":{"m":"wielki","f":"wielka","n":"wielkie","mp":"wielcy","other":"wielkie"},"acc":{"m":"wielkiego","f":"wielką","n":"wielkie","mp":"wielkich","other":"wielkie"}},{"lemma":"ważny","en":"important","nom":{"m":"ważny","f":"ważna","n":"ważne","mp":"ważni","other":"ważne"},"acc":{"m":"ważnego","f":"ważną","n":"ważne","mp":"ważnych","other":"ważne"}},{"lemma":"piękny","en":"beautiful","nom":{"m":"piękny","f":"piękna","n":"piękne","mp":"piękni","other":"piękne"},"acc":{"m":"pięknego","f":"piękną","n":"piękne","mp":"pięknych","other":"piękne"}},{"lemma":"ładny","en":"pretty / nice","nom":{"m":"ładny","f":"ładna","n":"ładne","mp":"ładni","other":"ładne"},"acc":{"m":"ładnego","f":"ładną","n":"ładne","mp":"ładnych","other":"ładne"}},{"lemma":"brzydki","en":"ugly","nom":{"m":"brzydki","f":"brzydka","n":"brzydkie","mp":"brzydcy","other":"brzydkie"},"acc":{"m":"brzydkiego","f":"brzydką","n":"brzydkie","mp":"brzydkich","other":"brzydkie"}},{"lemma":"szczęśliwy","en":"happy","nom":{"m":"szczęśliwy","f":"szczęśliwa","n":"szczęśliwe","mp":"szczęśliwi","other":"szczęśliwe"},"acc":{"m":"szczęśliwego","f":"szczęśliwą","n":"szczęśliwe","mp":"szczęśliwych","other":"szczęśliwe"}},{"lemma":"smutny","en":"sad","nom":{"m":"smutny","f":"smutna","n":"smutne","mp":"smutni","other":"smutne"},"acc":{"m":"smutnego","f":"smutną","n":"smutne","mp":"smutnych","other":"smutne"}},{"lemma":"ciepły","en":"warm","nom":{"m":"ciepły","f":"ciepła","n":"ciepłe","mp":"ciepli","other":"ciepłe"},"acc":{"m":"ciepłego","f":"ciepłą","n":"ciepłe","mp":"ciepłych","other":"ciepłe"}},{"lemma":"zimny","en":"cold","nom":{"m":"zimny","f":"zimna","n":"zimne","mp":"zimni","other":"zimne"},"acc":{"m":"zimnego","f":"zimną","n":"zimne","mp":"zimnych","other":"zimne"}},{"lemma":"szybki","en":"fast / quick","nom":{"m":"szybki","f":"szybka","n":"szybkie","mp":"szybcy","other":"szybkie"},"acc":{"m":"szybkiego","f":"szybką","n":"szybkie","mp":"szybkich","other":"szybkie"}},{"lemma":"wolny","en":"slow / free","nom":{"m":"wolny","f":