,"en":"single / alone","nom":{"m":"samotny","f":"samotna","n":"samotne","mp":"samotni","other":"samotne"},"acc":{"m":"samotnego","f":"samotną","n":"samotne","mp":"samotnych","other":"samotne"}},{"lemma":"rozwiedziony","en":"divorced","nom":{"m":"rozwiedziony","f":"rozwiedziona","n":"rozwiedzione","mp":"rozwiedzeni","other":"rozwiedzione"},"acc":{"m":"rozwiedzionego","f":"rozwiedzioną","n":"rozwiedzione","mp":"rozwiedzionych","other":"rozwiedzione"}},{"lemma":"niesamowity","en":"amazing","nom":{"m":"niesamowity","f":"niesamowita","n":"niesamowite","mp":"niesamowici","other":"niesamowite"},"acc":{"m":"niesamowitego","f":"niesamowitą","n":"niesamowite","mp":"niesamowitych","other":"niesamowite"}},{"lemma":"uroczy","en":"lovely","nom":{"m":"uroczy","f":"urocza","n":"urocze","mp":"uroczy","other":"urocze"},"acc":{"m":"uroczego","f":"uroczą","n":"urocze","mp":"uroczych","other":"urocze"}},{"lemma":"inspirujący","en":"inspiring","nom":{"m":"inspirujący","f":"inspirująca","n":"inspirujące","mp":"inspirujący","other":"inspirujące"},"acc":{"m":"inspirującego","f":"inspirującą","n":"inspirujące","mp":"inspirujących","other":"inspirujące"}},{"lemma":"błogi","en":"blissful","nom":{"m":"błogi","f":"błoga","n":"błogie","mp":"błodzy","other":"błogie"},"acc":{"m":"błogiego","f":"błogą","n":"błogie","mp":"błogich","other":"błogie"}}]}');
INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('en-pl-v1', 'lesson-04', 'adverbs', 40, 'Lesson 4 — Common adverbs', 'Polish adverbs are uninflected: one form covers every gender, number, and case. These ten carry a lot of weight in everyday speech — manner (szybko, dobrze, źle), degree (bardzo, trochę), location (tutaj), togetherness (razem), the willingness/gladness marker (chętnie) you hear constantly in invitations, plus a few time anchors (dzisiaj, jutro, teraz).', '{"id":"lesson-04","title":"Lesson 4 — Common adverbs","summary":"Polish adverbs are uninflected: one form covers every gender, number, and case. These ten carry a lot of weight in everyday speech — manner (szybko, dobrze, źle), degree (bardzo, trochę), location (tutaj), togetherness (razem), the willingness/gladness marker (chętnie) you hear constantly in invitations, plus a few time anchors (dzisiaj, jutro, teraz).","adverbs":[{"lemma":"bardzo","en":"very"},{"lemma":"dobrze","en":"well / good"},{"lemma":"szybko","en":"quickly / fast"},{"lemma":"trochę","en":"a little / a bit"},{"lemma":"tutaj","en":"here"},{"lemma":"razem","en":"together"},{"lemma":"dzisiaj","en":"today"},{"lemma":"jutro","en":"tomorrow"},{"lemma":"teraz","en":"now"},{"lemma":"chętnie","en":"gladly / willingly"}]}');
INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('en-pl-v1', 'lesson-05', 'phrases', 50, 'Lesson 5 — Phrases', 'Multi-sentence real-world phrases. Each group strings together a useful run of sentences you''d actually say — introductions, small-talk, asking for help — so the audio drill mirrors a real conversation, not isolated grammar drills.', '{"id":"lesson-05","title":"Lesson 5 — Phrases","summary":"Multi-sentence real-world phrases. Each group strings together a useful run of sentences you''d actually say — introductions, small-talk, asking for help — so the audio drill mirrors a real conversation, not isolated grammar drills.","groups":[{"id":"intro-rahul","title":"Introduction — Rahul","subtitle":"Meeting someone new and explaining what you do.","sentences":[{"pl":"Cześć, miło mi cię poznać.","en":"Hello, nice to meet you.","literal":"Hi, pleasant me you to-meet.","words":[{"pl":"Cześć,","en":"Hi,"},{"pl":"miło","en":"pleasant"},{"pl":"mi","en":"to-me"},{"pl":"cię","en":"you"},{"pl":"poznać.","en":"to-meet."}]},{"pl":"Mam na imię Rahul.","en":"My name is Rahul.","literal":"I-have on name Rahul.","words":[{"pl":"Mam","en":"I-have"},{"pl":"na","en":"on"},{"pl":"imię","en":"name"},{"pl":"Rahul.","en":"Rahul."}]},{"pl":"Jestem człowiekiem szczerym.","en":"I am an honest person.","literal":"I-am person honest.","words":[{"pl":"Jestem","en":"I-am"},{"pl":"człowiekiem","en":"person"},{"pl":"szczerym.","en":"honest."}]},{"pl":"Jestem z Austin, w Teksasie.","en":"I am from Austin, Texas.","literal":"I-am from Austin, in Texas.","words":[{"pl":"Jestem","en":"I-am"},{"pl":"z","en":"from"},{"pl":"Austin,","en":"Austin,"},{"pl":"w","en":"in"},{"pl":"Teksasie.","en":"Texas."}]},{"pl":"To tam zwykle mieszka Elon Musk.","en":"That''s where Elon Musk usually lives.","literal":"It there usually lives Elon Musk.","words":[{"pl":"To","en":"it"},{"pl":"tam","en":"there"},{"pl":"zwykle","en":"usually"},{"pl":"mieszka","en":"lives"},{"pl":"Elon","en":"Elon"},{"pl":"Musk.","en":"Musk."}]},{"pl":"Mieszkam obok głównej siedziby Tesli i fabryki humanoidalnych robotów.","en":"I live next to the Tesla headquarters and humanoid robot factory.","literal":"I-live next-to main headquarters of-Tesla and factory of-humanoid robots.","words":[{"pl":"Mieszkam","en":"I-live"},{"pl":"obok","en":"next-to"},{"pl":"głównej","en":"main"},{"pl":"siedziby","en":"headquarters"},{"pl":"Tesli","en":"of-Tesla"},{"pl":"i","en":"and"},{"pl":"fabryki","en":"factory"},{"pl":"humanoidalnych","en":"of-humanoid"},{"pl":"robotów.","en":"robots."}]},{"pl":"Niedawno przyjechałem do Polski.","en":"I just came to Poland recently.","literal":"Recently I-came to Poland.","words":[{"pl":"Niedawno","en":"recently"},{"pl":"przyjechałem","en":"I-came"},{"pl":"do","en":"to"},{"pl":"Polski.","en":"Poland."}]},{"pl":"Więc mój polski nie jest jeszcze najlepszy.","en":"So my Polish is not very good yet.","literal":"So my Polish not is yet best.","words":[{"pl":"Więc","en":"so"},{"pl":"mój","en":"my"},{"pl":"polski","en":"Polish"},{"pl":"nie","en":"not"},{"pl":"jest","en":"is"},{"pl":"jeszcze","en":"yet"},{"pl":"najlepszy.","en":"best."}]},{"pl":"Pracuję nad nowym startupem AI.","en":"I''m working on a new AI startup.","literal":"I-work on new startup AI.","words":[{"pl":"Pracuję","en":"I-work"},{"pl":"nad","en":"on"},{"pl":"nowym","en":"new"},{"pl":"startupem","en":"startup"},{"pl":"AI.","en":"AI."}]},{"pl":"Łączy społeczność, fitness i uprawę roślin.","en":"It combines community, fitness, and plant cultivation.","literal":"Combines community, fitness and cultivation of-plants.","words":[{"pl":"Łączy","en":"combines"},{"pl":"społeczność,","en":"community,"},{"pl":"fitness","en":"fitness"},{"pl":"i","en":"and"},{"pl":"uprawę","en":"cultivation"},{"pl":"roślin.","en":"of-plants."}]},{"pl":"Niedługo będziemy organizować wydarzenia.","en":"We''ll be organizing events soon.","literal":"Soon we-will-be to-organize events.","words":[{"pl":"Niedługo","en":"soon"},{"pl":"będziemy","en":"we-will-be"},{"pl":"organizować","en":"to-organize"},{"pl":"wydarzenia.","en":"events."}]},{"pl":"Jeśli brzmi to ciekawie, mogę cię zaprosić.","en":"If this sounds interesting, I can invite you.","literal":"If sounds this interestingly, I-can you to-invite.","words":[{"pl":"Jeśli","en":"if"},{"pl":"brzmi","en":"sounds"},{"pl":"to","en":"this"},{"pl":"ciekawie,","en":"interestingly,"},{"pl":"mogę","en":"I-can"},{"pl":"cię","en":"you"},{"pl":"zaprosić.","en":"to-invite."}]},{"pl":"Ale wyglądasz pięknie w każdym języku.","en":"But you look beautiful in any language.","literal":"But you-look beautifully in every language.","words":[{"pl":"Ale","en":"but"},{"pl":"wyglądasz","en":"you-look"},{"pl":"pięknie","en":"beautifully"},{"pl":"w","en":"in"},{"pl":"każdym","en":"every"},{"pl":"języku.","en":"language."}]},{"pl":"Tego nie da się opisać słowami.","en":"This is beyond words.","literal":"This not can self describe with-words.","words":[{"pl":"Tego","en":"this"},{"pl":"nie","en":"not"},{"pl":"da","en":"can"},{"pl":"się","en":"self"},{"pl":"opisać","en":"describe"},{"pl":"słowami.","en":"with-words."}]}]},{"id":"language-icebreakers","title":"Language icebreakers","subtitle":"Honest small-talk when you''re new to Polish — apologize, ask for help, switch to English.","sentences":[{"pl":"Mój polski jest fatalny.","en":"My Polish is terrible.","literal":"My Polish is terrible.","words":[{"pl":"Mój","en":"my"},{"pl":"polski","en":"Polish"},{"pl":"jest","en":"is"},{"pl":"fatalny.","en":"terrible."}]},{"pl":"Mam nadzieję na szybką poprawę.","en":"I am hopeful of rapid improvement.","literal":"I-have hope for rapid improvement.","words":[{"pl":"Mam","en":"I-have"},{"pl":"nadzieję","en":"hope"},{"pl":"na","en":"for"},{"pl":"szybką","en":"rapid"},{"pl":"poprawę.","en":"improvement."}]},{"pl":"Mój polski nie jest świetny.","en":"My Polish is not great.","literal":"My Polish not is great.","words":[{"pl":"Mój","en":"my"},{"pl":"polski","en":"Polish"},{"pl":"nie","en":"not"},{"pl":"jest","en":"is"},{"pl":"świetny.","en":"great."}]},{"pl":"Tak naprawdę nic nie rozumiem.","en":"I can''t really understand anything.","literal":"So really nothing not I-understand.","words":[{"pl":"Tak","en":"so"},{"pl":"naprawdę","en":"really"},{"pl":"nic","en":"nothing"},{"pl":"nie","en":"not"},{"pl":"rozumiem.","en":"I-understand."}]},{"pl":"Moje okulary czasami potrafią słuchać i tłumaczyć.","en":"My glasses can listen and translate sometimes.","literal":"My glasses sometimes can listen and translate.","words":[{"pl":"Moje","en":"my"},{"pl":"okulary","en":"glasses"},{"pl":"czasami","en":"sometimes"},{"pl":"potrafią","en":"can"},{"pl":"słuchać","en":"listen"},{"pl":"i","en":"and"},{"pl":"tłumaczyć.","en":"translate."}]},{"pl":"Cieszę się, że mówisz po angielsku.","en":"I''m glad you speak English.","literal":"I-am-glad self, that you-speak in English.","words":[{"pl":"Cieszę","en":"I-am-glad"},{"pl":"się,","en":"self,"},{"pl":"że","en":"that"},{"pl":"mówisz","en":"you-speak"},{"pl":"po","en":"in"},{"pl":"angielsku.","en":"English."}]},{"pl":"Czy mogę mówić po angielsku?","en":"Can I speak in English?","literal":"Whether I-can to-speak in English?","words":[{"pl":"Czy","en":"whether"},{"pl":"mogę","en":"I-can"},{"pl":"mówić","en":"to-speak"},{"pl":"po","en":"in"},{"pl":"angielsku?","en":"English?"}]},{"pl":"Proszę mówić wolniej.","en":"Please speak more slowly.","literal":"Please to-speak more-slowly.","words":[{"pl":"Proszę","en":"please"},{"pl":"mówić","en":"to-speak"},{"pl":"wolniej.","en":"more-slowly."}]},{"pl":"Nie rozumiem.","en":"I don''t understand.","literal":"Not I-understand.","words":[{"pl":"Nie","en":"not"},{"pl":"rozumiem.","en":"I-understand."}]},{"pl":"Możesz powtórzyć?","en":"Can you repeat that?","literal":"You-can to-repeat?","words":[{"pl":"Możesz","en":"you-can"},{"pl":"powtórzyć?","en":"to-repeat?"}]},{"pl":"Uczę się polskiego.","en":"I''m learning Polish.","literal":"I-learn self of-Polish.","words":[{"pl":"Uczę","en":"I-learn"},{"pl":"się","en":"self"},{"pl":"polskiego.","en":"of-Polish."}]},{"pl":"Przepraszam za mój polski.","en":"Sorry about my Polish.","literal":"Sorry for my Polish.","words":[{"pl":"Przepraszam","en":"sorry"},{"pl":"za","en":"for"},{"pl":"mój","en":"my"},{"pl":"polski.","en":"Polish."}]},{"pl":"Uczę się polskiego z aplikacją, którą zbudowałem.","en":"I study Polish with an application I built.","literal":"I-learn self of-Polish with app, which I-built.","words":[{"pl":"Uczę","en":"I-learn"},{"pl":"się","en":"self"},{"pl":"polskiego","en":"of-Polish"},{"pl":"z","en":"with"},{"pl":"aplikacją,","en":"app,"},{"pl":"którą","en":"which"},{"pl":"zbudowałem.","en":"I-built."}]},{"pl":"Jak widzisz, nie jest bardzo dobra.","en":"As you can tell, it''s not very good.","literal":"As you-see, not is very good.","words":[{"pl":"Jak","en":"as"},{"pl":"widzisz,","en":"you-see,"},{"pl":"nie","en":"not"},{"pl":"jest","en":"is"},{"pl":"bardzo","en":"very"},{"pl":"dobra.","en":"good."}]},{"pl":"Czy mówisz trochę po angielsku?","en":"Do you speak a little English?","literal":"Whether you-speak a-little in English?","words":[{"pl":"Czy","en":"whether"},{"pl":"mówisz","en":"you-speak"},{"pl":"trochę","en":"a-little"},{"pl":"po","en":"in"},{"pl":"angielsku?","en":"English?"}]},{"pl":"Szukam korepetytora polskiego.","en":"I''m looking for a Polish tutor.","literal":"I-look-for of-tutor of-Polish.","words":[{"pl":"Szukam","en":"I-look-for"},{"pl":"korepetytora","en":"tutor"},{"pl":"polskiego.","en":"Polish."}]}]},{"id":"welcome-to-poland","title":"Welcome to Poland","subtitle":"A welcome for someone arriving in Poland, with a little end-of-days optimism.","sentences":[{"pl":"Mam nadzieję, że podróż była dobra.","en":"I hope you had a good trip.","literal":"I-have hope, that trip was good.","words":[{"pl":"Mam","en":"I-have"},{"pl":"nadzieję,","en":"hope,"},{"pl":"że","en":"that"},{"pl":"podróż","en":"trip"},{"pl":"była","en":"was"},{"pl":"dobra.","en":"good."}]},{"pl":"Witaj w ojczyźnie, w Polsce.","en":"Welcome to the fatherland, Poland.","literal":"Welcome in fatherland, in Poland.","words":[{"pl":"Witaj","en":"welcome"},{"pl":"w","en":"in"},{"pl":"ojczyźnie,","en":"fatherland,"},{"pl":"w","en":"in"},{"pl":"Polsce.","en":"Poland."}]},{"pl":"Myślę, że spodoba ci się tutaj.","en":"I think you will like it here.","literal":"I-think, that will-please to-you self here.","words":[{"pl":"Myślę,","en":"I-think,"},{"pl":"że","en":"that"},{"pl":"spodoba","en":"will-please"},{"pl":"ci","en":"to-you"},{"pl":"się","en":"self"},{"pl":"tutaj.","en":"here."}]},{"pl":"Przyszłość może być budowana tutaj.","en":"The future may be built here.","literal":"Future can be built here.","words":[{"pl":"Przyszłość","en":"future"},{"pl":"może","en":"can"},{"pl":"być","en":"be"},{"pl":"budowana","en":"built"},{"pl":"tutaj.","en":"here."}]},{"pl":"Zanim roboty nas wszystkich zabiją.","en":"before the robots kill us all.","literal":"Before robots us all kill.","words":[{"pl":"Zanim","en":"before"},{"pl":"roboty","en":"robots"},{"pl":"nas","en":"us"},{"pl":"wszystkich","en":"all"},{"pl":"zabiją.","en":"kill."}]}]}]}');
INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('en-pl-v1', 'lesson-06', 'nouns', 60, 'Lesson 6 — Core nouns', 'High-frequency Polish nouns, each shown across its three workhorse cases — nominative (subject), accusative (direct object), and genitive (''of'' / after ''nie ma'' / after most prepositions) — in both singular and plural. Each noun is tagged with its gender (m / f / n). Masculine accusative depends on animacy: animate nouns (people, animals) take a genitive-like accusative (widzę psa, widzę syna), while inanimate masculine accusative equals the nominative (widzę dom, widzę stół). The stored forms already bake this in.', '{"id":"lesson-06","title":"Lesson 6 — Core nouns","summary":"High-frequency Polish nouns, each shown across its three workhorse cases — nominative (subject), accusative (direct object), and genitive (''of'' / after ''nie ma'' / after most prepositions) — in both singular and plural. Each noun is tagged with its gender (m / f / n). Masculine accusative depends on animacy: animate nouns (people, animals) take a genitive-like accusative (widzę psa, widzę syna), while inanimate masculine accusative equals the nominative (widzę dom, widzę stół). The stored forms already bake this in.","nouns":[{"lemma":"dom","en":"house / home","gender":"m","nom":{"sg":"dom","pl":"domy"},"acc":{"sg":"dom","pl":"domy"},"gen":{"sg":"domu","pl":"domów"}},{"lemma":"kot","en":"cat","gender":"m","nom":{"sg":"kot","pl":"koty"},"acc":{"sg":"kota","pl":"koty"},"gen":{"sg":"kota","pl":"kotów"}},{"lemma":"pies","en":"dog","gender":"m","nom":{"sg":"pies","pl":"psy"},"acc":{"sg":"psa","pl":"psy"},"gen":{"sg":"psa","pl":"psów"}},{"lemma":"kobieta","en":"woman","gender":"f","nom":{"sg":"kobieta","pl":"kobiety"},"acc":{"sg":"kobietę","pl":"kobiety"},"gen":{"sg":"kobiety","pl":"kobiet"}},{"lemma":"mężczyzna","en":"man","gender":"m","nom":{"sg":"mężczyzna","pl":"mężczyźni"},"acc":{"sg":"mężczyznę","pl":"mężczyzn"},"gen":{"sg":"mężczyzny","pl":"mężczyzn"}},{"lemma":"dziecko","en":"child","gender":"n","nom":{"sg":"dziecko","pl":"dzieci"},"acc":{"sg":"dziecko","pl":"dzieci"},"gen":{"sg":"dziecka","pl":"dzieci"}},{"lemma":"mama","en":"mom","gender":"f","nom":{"sg":"mama","pl":"mamy"},"acc":{"sg":"mamę","pl":"mamy"},"gen":{"sg":"mamy","pl":"mam"}},{"lemma":"brat","en":"brother","gender":"m","nom":{"sg":"brat","pl":"bracia"},"acc":{"sg":"brata","pl":"braci"},"gen":{"sg":"brata","pl":"braci"}},{"lemma":"siostra","en":"sister","gender":"f","nom":{"sg":"siostra","pl":"siostry"},"acc":{"sg":"siostrę","pl":"siostry"},"gen":{"sg":"siostry","pl":"sióstr"}},{"lemma":"syn","en":"son","gender":"m","nom":{"sg":"syn","pl":"synowie"},"acc":{"sg":"syna","pl":"synów"},"gen":{"sg":"syna","pl":"synów"}},{"lemma":"człowiek","en":"person","gender":"m","nom":{"sg":"człowiek","pl":"ludzie"},"acc":{"sg":"człowieka","pl":"ludzi"},"gen":{"sg":"człowieka","pl":"ludzi"}},{"lemma":"woda","en":"water","gender":"f","nom":{"sg":"woda","pl":"wody"},"acc":{"sg":"wodę","pl":"wody"},"gen":{"sg":"wody","pl":"wód"}},{"lemma":"kawa","en":"coffee","gender":"f","nom":{"sg":"kawa","pl":"kawy"},"acc":{"sg":"kawę","pl":"kawy"},"gen":{"sg":"kawy","pl":"kaw"}},{"lemma":"herbata","en":"tea","gender":"f","nom":{"sg":"herbata","pl":"herbaty"},"acc":{"sg":"herbatę","pl":"herbaty"},"gen":{"sg":"herbaty","pl":"herbat"}},{"lemma":"chleb","en":"bread","gender":"m","nom":{"sg":"chleb","pl":"chleby"},"acc":{"sg":"chleb","pl":"chleby"},"gen":{"sg":"chleba","pl":"chlebów"}},{"lemma":"jedzenie","en":"food","gender":"n","nom":{"sg":"jedzenie","pl":"jedzenia"},"acc":{"sg":"jedzenie","pl":"jedzenia"},"gen":{"sg":"jedzenia","pl":"jedzeń"}},{"lemma":"książka","en":"book","gender":"f","nom":{"sg":"książka","pl":"książki"},"acc":{"sg":"książkę","pl":"książki"},"gen":{"sg":"książki","pl":"książek"}},{"lemma":"telefon","en":"phone","gender":"m","nom":{"sg":"telefon","pl":"telefony"},"acc":{"sg":"telefon","pl":"telefony"},"gen":{"sg":"telefonu","pl":"telefonów"}},{"lemma":"samochód","en":"car","gender":"m","nom":{"sg":"samochód","pl":"samochody"},"acc":{"sg":"samochód","pl":"samochody"},"gen":{"sg":"samochodu","pl":"samochodów"}},{"lemma":"stół","en":"table","gender":"m","nom":{"sg":"stół","pl":"stoły"},"acc":{"sg":"stół","pl":"stoły"},"gen":{"sg":"stołu","pl":"stołów"}},{"lemma":"krzesło","en":"chair","gender":"n","nom":{"sg":"krzesło","pl":"krzesła"},"acc":{"sg":"krzesło","pl":"krzesła"},"gen":{"sg":"krzesła","pl":"krzeseł"}},{"lemma":"okno","en":"window","gender":"n","nom":{"sg":"okno","pl":"okna"},"acc":{"sg":"okno","pl":"okna"},"gen":{"sg":"okna","pl":"okien"}},{"lemma":"mieszkanie","en":"apartment / flat","gender":"n","nom":{"sg":"mieszkanie","pl":"mieszkania"},"acc":{"sg":"mieszkanie","pl":"mieszkania"},"gen":{"sg":"mieszkania","pl":"mieszkań"}},{"lemma":"miasto","en":"city / town","gender":"n","nom":{"sg":"miasto","pl":"miasta"},"acc":{"sg":"miasto","pl":"miasta"},"gen":{"sg":"miasta","pl":"miast"}},{"lemma":"ulica","en":"street","gender":"f","nom":{"sg":"ulica","pl":"ulice"},"acc":{"sg":"ulicę","pl":"ulice"},"gen":{"sg":"ulicy","pl":"ulic"}},{"lemma":"sklep","en":"shop / store","gender":"m","nom":{"sg":"sklep","pl":"sklepy"},"acc":{"sg":"sklep","pl":"sklepy"},"gen":{"sg":"sklepu","pl":"sklepów"}},{"lemma":"szkoła","en":"school","gender":"f","nom":{"sg":"szkoła","pl":"szkoły"},"acc":{"sg":"szkołę","pl":"szkoły"},"gen":{"sg":"szkoły","pl":"szkół"}},{"lemma":"praca","en":"work / job","gender":"f","nom":{"sg":"praca","pl":"prace"},"acc":{"sg":"pracę","pl":"prace"},"gen":{"sg":"pracy","pl":"prac"}},{"lemma":"noc","en":"night","gender":"f","nom":{"sg":"noc","pl":"noce"},"acc":{"sg":"noc","pl":"noce"},"gen":{"sg":"nocy","pl":"nocy"}},{"lemma":"miłość","en":"love","gender":"f","nom":{"sg":"miłość","pl":"miłości"},"acc":{"sg":"miłość","pl":"miłości"},"gen":{"sg":"miłości","pl":"miłości"}},{"lemma":"komputer","en":"computer","gender":"m","nom":{"sg":"komputer","pl":"komputery"},"acc":{"sg":"komputer","pl":"komputery"},"gen":{"sg":"komputera","pl":"komputerów"}},{"lemma":"karta kredytowa","en":"credit card","gender":"f","nom":{"sg":"karta kredytowa","pl":"karty kredytowe"},"acc":{"sg":"kartę kredytową","pl":"karty kredytowe"},"gen":{"sg":"karty kredytowej","pl":"kart kredytowych"}},{"lemma":"chłopak","en":"boyfriend","gender":"m","nom":{"sg":"chłopak","pl":"chłopaki"},"acc":{"sg":"chłopaka","pl":"chłopaków"},"gen":{"sg":"chłopaka","pl":"chłopaków"}},{"lemma":"dziewczyna","en":"girlfriend","gender":"f","nom":{"sg":"dziewczyna","pl":"dziewczyny"},"acc":{"sg":"dziewczynę","pl":"dziewczyny"},"gen":{"sg":"dziewczyny","pl":"dziewczyn"}}]}');
INSERT OR REPLACE INTO content_lessons (content_version_id, lesson_id, lesson_type, sort_order, title, summary, payload_json)
VALUES ('pl-en-v1', 'pl-en-phrases', 'reversed_phrases', 10, 'Zwroty angielskie', 'Polish prompts with English study targets, generated from the existing phrase bank.', '{"schema":"langbangml.reversed-phrases.v1","id":"pl-en-phrases","title":"Zwroty angielskie","summary":"Polish prompts with English study targets, generated from the existing phrase bank.","sourceLocale":"pl-PL","targetLocale":"en-US","groups":[{"id":"intro-rahul","title":"Introduction — Rahul","subtitle":"Meeting someone new and explaining what you do.","sentences":[{"source":"Cześć, miło mi cię poznać.","target":"Hello, nice to meet you.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Mam na imię Rahul.","target":"My name is Rahul.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Jestem człowiekiem szczerym.","target":"I am an honest person.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Jestem z Austin, w Teksasie.","target":"I am from Austin, Texas.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"To tam zwykle mieszka Elon Musk.","target":"That''s where Elon Musk usually lives.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Mieszkam obok głównej siedziby Tesli i fabryki humanoidalnych robotów.","target":"I live next to the Tesla headquarters and humanoid robot factory.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Niedawno przyjechałem do Polski.","target":"I just came to Poland recently.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Więc mój polski nie jest jeszcze najlepszy.","target":"So my Polish is not very good yet.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Pracuję nad nowym startupem AI.","target":"I''m working on a new AI startup.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Łączy społeczność, fitness i uprawę roślin.","target":"It combines community, fitness, and plant cultivation.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Niedługo będziemy organizować wydarzenia.","target":"We''ll be organizing events soon.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Jeśli brzmi to ciekawie, mogę cię zaprosić.","target":"If this sounds interesting, I can invite you.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Ale wyglądasz pięknie w każdym języku.","target":"But you look beautiful in any language.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Tego nie da się opisać słowami.","target":"This is beyond words.","sourceLocale":"pl-PL","targetLocale":"en-US"}]},{"id":"language-icebreakers","title":"Language icebreakers","subtitle":"Honest small-talk when you''re new to Polish — apologize, ask for help, switch to English.","sentences":[{"source":"Mój polski jest fatalny.","target":"My Polish is terrible.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Mam nadzieję na szybką poprawę.","target":"I am hopeful of rapid improvement.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Mój polski nie jest świetny.","target":"My Polish is not great.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Tak naprawdę nic nie rozumiem.","target":"I can''t really understand anything.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Moje okulary czasami potrafią słuchać i tłumaczyć.","target":"My glasses can listen and translate sometimes.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Cieszę się, że mówisz po angielsku.","target":"I''m glad you speak English.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Czy mogę mówić po angielsku?","target":"Can I speak in English?","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Proszę mówić wolniej.","target":"Please speak more slowly.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Nie rozumiem.","target":"I don''t understand.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Możesz powtórzyć?","target":"Can you repeat that?","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Uczę się polskiego.","target":"I''m learning Polish.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Przepraszam za mój polski.","target":"Sorry about my Polish.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Uczę się polskiego z aplikacją, którą zbudowałem.","target":"I study Polish with an application I built.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Jak widzisz, nie jest bardzo dobra.","target":"As you can tell, it''s not very good.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Czy mówisz trochę po angielsku?","target":"Do you speak a little English?","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Szukam korepetytora polskiego.","target":"I''m looking for a Polish tutor.","sourceLocale":"pl-PL","targetLocale":"en-US"}]},{"id":"welcome-to-poland","title":"Welcome to Poland","subtitle":"A welcome for someone arriving in Poland, with a little end-of-days optimism.","sentences":[{"source":"Mam nadzieję, że podróż była dobra.","target":"I hope you had a good trip.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Witaj w ojczyźnie, w Polsce.","target":"Welcome to the fatherland, Poland.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Myślę, że spodoba ci się tutaj.","target":"I think you will like it here.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Przyszłość może być budowana tutaj.","target":"The future may be built here.","sourceLocale":"pl-PL","targetLocale":"en-US"},{"source":"Zanim roboty nas wszystkich zabiją.","target":"before the robots kill us all.","sourceLocale":"pl-PL","targetLocale":"en-US"}]}]}');
